class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class BSTIterator:

    def __init__(self, root: TreeNode):
        self.stack = []
        self._push_leftmost_path(root)

    def _push_leftmost_path(self, node: TreeNode):
        """
        Helper function to push all nodes on the leftmost path
        from the given node onto the stack.
        """
        while node:
            self.stack.append(node)
            node = node.left

    def next(self) -> int:
        """
        Returns the next smallest number.
        """
        if not self.has_next():
            raise StopIteration("No more elements in BST")

        current_node = self.stack.pop()
        # If there's a right child, we need to add its leftmost path to the stack
        if current_node.right:
            self._push_leftmost_path(current_node.right)

        return current_node.val

    def has_next(self) -> bool:
        """
        Returns whether we have a next smallest number.
        """
        return len(self.stack) > 0
